```csharp
public interface IBaseRepository<TEntity> where TEntity : class
{
    IEnumerable<TEntity> GetAll();
    TEntity GetById(object id);
    TEntity FindByDynamic(Expression<Func<TEntity, bool>> expression);
    TEntity FindByDynamic(Expression<Func<TEntity, bool>> expression, params object[] parameters);
}

public class BaseRepository<TEntity> : IBaseRepository<TEntity> where TEntity : class
{
    protected readonly DbContext _context;
    protected readonly DbSet<TEntity> _dbSet;

    public BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = _context.Set<TEntity>();
    }

    public IEnumerable<TEntity> GetAll()
    {
        return _dbSet.ToList();
    }

    public TEntity GetById(object id)
    {
        return _dbSet.Find(id);
    }

    public TEntity FindByDynamic(Expression<Func<TEntity, bool>> expression)
    {
        return _dbSet.AsNoTracking().FirstOrDefault(expression);
    }

    public TEntity FindByDynamic(Expression<Func<TEntity, bool>> expression, params object[] parameters)
    {
        return _dbSet.AsNoTracking().FirstOrDefault(expression, parameters);
    }
}
